    body.content,
    body.messages?.[0]?.content,
    primaryMessage.processed_message_content,
    primaryMessage.content
  )
);

const hasText = content.length > 0;

const mediaType = hasAttachment
  ? clean(firstAttachment.file_type || firstAttachment.type || firstAttachment.content_type || "attachment").toLowerCase()
  : "none";

const messageModality = hasAttachment && hasText
  ? `${mediaType}_with_text`
  : hasAttachment
    ? `${mediaType}_only`
    : hasText
      ? "text_only"
      : "unknown";

if (event && event !== "message_created") {
  return ignored("evento_nao_message_created");
}

if (!isIncoming) {
  return ignored("mensagem_nao_incoming", {
    message_type: messageType,
    sender_type: senderType,
  });
}

if (isPrivate) {
  return ignored("mensagem_privada");
}

if (!canReply) {
  return ignored("conversa_sem_permissao_de_resposta");
}

if (hasOptoutLabel) {
  return ignored("label_99_optout", { labels });
}

if (hasHumanLabel) {
  return ignored("label_humano_assumiu", { labels });
}

if (!hasJuliaLabel) {
  return ignored("sem_label_julia", { labels });
}

if (!shouldProcessByLabels) {
  return ignored("labels_nao_permitem_julia", { labels });
}

if (!content && !hasAttachment) {
  return ignored("mensagem_sem_texto_e_sem_anexo");
}

const accountId = body.account?.id || conversation.account_id || null;
const inboxId = body.inbox?.id || conversation.inbox_id || null;
const conversationId = conversation.id || primaryMessage.conversation_id || null;
const contactId = sender.id || primaryMessage.sender_id || conversation.meta?.sender?.id || null;

const phone = onlyDigits(
  firstFilled(
    sender.phone_number,
    sender.identifier,
    primaryMessage.sender?.phone_number
  )
);

const sessionKey = phone || contactId || conversationId || body.id || Date.now();
const sessionId = `julia-chatwoot-a${accountId || "x"}-${sessionKey}`;

const contactName = firstFilled(sender.name, conversation.meta?.sender?.name);

const attachmentSummary = hasAttachment
  ? attachments.map((attachment, index) => {
      const kind = firstFilled(
        attachment.file_type,
        attachment.content_type,
        attachment.message_type,
        "anexo"
      );

      const url = firstFilled(
        attachment.data_url,
        attachment.download_url,
        attachment.file_url,
        attachment.url
      );

      return `Anexo ${index + 1}: ${kind}${url ? ` - ${url}` : ""}`;
    }).join("\n")
  : "";

const safeContent = content
  ? [
      content,
      attachmentSummary ? `\n\nContexto de mídia recebida:\n${attachmentSummary}` : "",
    ].join("").trim()
  : `[Mensagem com anexo sem legenda. message_modality=${messageModality || "unknown"}]`;

const custom = sender.custom_attributes || {};
const additional = conversation.additional_attributes || {};

const companyName = firstFilled(
  custom.empresa,
  custom.company_name,
  custom.nome_empresa,
  additional.empresa,
  additional.company_name
);

const leadNiche = firstFilled(
  custom.nicho,
  custom.segmento,
  additional.nicho,
  additional.segmento
);

const googleRating = firstFilled(
  custom.classificacao,
  custom.nota_google,
  custom.google_rating,
  additional.classificacao,
  additional.nota_google
);

const googleReviews = firstFilled(
  custom.avaliacoes,
  custom.google_reviews,
  additional.avaliacoes,
  additional.google_reviews
);

const googleBusinessProfile = firstFilled(
  custom.gmn,
  custom.google_business_profile,
  custom.link_gmn,
  additional.gmn,
  additional.google_business_profile,
  additional.link_gmn
);

const cityState = firstFilled(
  custom.cidade_estado,
  custom.cidade,
  additional.cidade_estado,
  additional.cidade
);

const origem = firstFilled(
  custom.origem,
  additional.origem,
  leadSource.source_type
);

const campanha = firstFilled(custom.campanha, additional.campanha);
const anuncio = firstFilled(custom.anuncio, additional.anuncio);

const linkRastreavel = firstFilled(
  custom.link_rastreavel,
  additional.link_rastreavel
);

return [{
  json: {
    action: "agent",
    sessionId,
    chatInput: safeContent,

    lead: {
      id: contactId || sessionKey,
      name: contactName,
      phone,

      company_name: companyName,
      niche: leadNiche,
      city_state: cityState,

      google_rating: googleRating,
      google_reviews: googleReviews,
      google_business_profile: googleBusinessProfile,

      origem,
      campanha,
      anuncio,
      link_rastreavel: linkRastreavel,

      source: leadSource.source_type,
      source_type: leadSource.source_type,
      source_label: leadSource.source_label,
      source_description: leadSource.source_description,

      current_stage: "descoberta",
      responsible_name: "",
      responsible_phone: "",
      fit_score: null,
      lead_status: "EM_ANDAMENTO",
    },

    message: {
      role: "lead",
      content,
      content_for_ai: safeContent,

      has_text: hasText,
      has_attachment: hasAttachment,

      content_type: messageModality,
      message_modality: messageModality,
      raw_content_type: rawContentType,

      data_url: dataUrl,
      media_type: mediaType,

      created_at: firstFilled(body.created_at, primaryMessage.updated_at, nowIso()),
    },

    conversation: {
      is_test: false,
      memory_enabled: true,
      history_source: "chatwoot_subworkflow",

      labels,
      has_julia_label: hasJuliaLabel,
      has_human_label: hasHumanLabel,
      has_optout_label: hasOptoutLabel,

      lead_source_type: leadSource.source_type,
      source_label: leadSource.source_label,
      playbook_mode: leadSource.playbook_mode,

      status: clean(conversation.status),
      unread_count: conversation.unread_count || 0,
      assignee_id: conversation.assignee_id || null,
      team_id: conversation.meta?.team?.id || null,
      team_name: conversation.meta?.team?.name || "",
    },

    chatwoot: {
      account_id: accountId,
      inbox_id: inboxId,
      conversation_id: conversationId,
      contact_id: contactId,
      message_id: body.id || primaryMessage.id || null,
      source_id: firstFilled(body.source_id, primaryMessage.source_id),
      delivery_id: headers["x-chatwoot-delivery"] || "",
      webhook_url: envelope.webhookUrl || "",
      raw_event: event || "message_created",
    },

    routing: {
      should_process: true,
      should_reply: true,
      should_handoff: false,
      route_action: "agent",
      direct_handoff_motivo: "",
      channel: "chatwoot_whatsapp",
      agent_name: "Julia",
    },

    labels_update: {
      add: [],
      remove: [],
    },

    agent: {
      memory_session_id: sessionId,

      lead_source_type: leadSource.source_type,
      source_label: leadSource.source_label,
      playbook_mode: leadSource.playbook_mode,
      source_description: leadSource.source_description,

      ai_input: [
        "MENSAGEM ATUAL DO LEAD:",
        safeContent,
        "",
        "ORIGEM DETECTADA POR LABEL:",
        `Tipo: ${leadSource.source_type}`,
        `Etiqueta: ${leadSource.source_label || "não informada"}`,
        `Descrição: ${leadSource.source_description}`,
      ].join("\n"),
    },

    debug: {
      normaliza_entrada_chatwoot_version: NORMALIZA_ENTRADA_CHATWOOT_VERSION,

      labels,
      labels_source: "Lista Etiquetas",

      has_julia_label: hasJuliaLabel,
      has_human_label: hasHumanLabel,
      has_optout_label: hasOptoutLabel,
      should_process_by_labels: shouldProcessByLabels,

      lead_source_type: leadSource.source_type,
      source_label: leadSource.source_label,
      playbook_mode: leadSource.playbook_mode,

      original_message_type: messageType,
      numeric_message_type: numericMessageType,
      sender_type: senderType,

      has_attachment: hasAttachment,
      content_type: messageModality,
      message_modality: messageModality,

      data_url: dataUrl,
    },
  },
}];

